private static void SeedScrambleVariation(PixelBuffer input, PixelBuffer output, int size, int seed, float intensity)
{
    output.ParallelForEachPixel((x, y) =>
    {
        var (r, g, b, a) = input.GetPixel(x, y);

        // Per-pixel noise offset using hash
        var noiseX = HashToUnit(x * 7 + seed, y * 13 + seed * 3, 111);
        var noiseY = HashToUnit(x * 11 + seed * 5, y * 7 + seed, 222);
        var noiseZ = HashToUnit(x * 3 + seed * 7, y * 11 + seed * 11, 333);

        var shift = intensity * 0.15f;
        r = Math.Clamp(r + (noiseX - 0.5f) * shift, 0f, 1f);
        g = Math.Clamp(g + (noiseY - 0.5f) * shift, 0f, 1f);
        b = Math.Clamp(b + (noiseZ - 0.5f) * shift, 0f, 1f);

        output.SetPixel(x, y, r, g, b, a);
    });
}

private static void ParameterNoiseVariation(PixelBuffer input, PixelBuffer output, int size, int seed, float intensity)
{
    // Generate a noise field and blend it with the input
    var noiseField = new PixelBuffer(size, size);
    noiseField.ParallelForEachPixel((x, y) =>
    {
        var n = TileableFractalNoise(x / (float)size * 4f, y / (float)size * 4f, 4, 3, 0.5f, 2f, seed);
        noiseField.SetPixel(x, y, n, n, n, 1f);
    });

    output.ParallelForEachPixel((x, y) =>
    {
        var (r, g, b, a) = input.GetPixel(x, y);
        var (nr, _, _, _) = noiseField.GetPixel(x, y);

        var blend = intensity * 0.4f;
        r = Math.Clamp(r + (nr - 0.5f) * blend, 0f, 1f);
        g = Math.Clamp(g + (nr - 0.5f) * blend, 0f, 1f);
        b = Math.Clamp(b + (nr - 0.5f) * blend, 0f, 1f);

        output.SetPixel(x, y, r, g, b, a);
    });
}

private static void StyleBlendVariation(PixelBuffer input, PixelBuffer output, int size, int seed, float intensity, bool keepStructure)
{
    output.ParallelForEachPixel((x, y) =>
    {
        var (r, g, b, a) = input.GetPixel(x, y);

        if (keepStructure)
        {
            // Perturb hue and saturation while preserving luminance
            var lum = r * 0.299f + g * 0.587f + b * 0.114f;
            var hueShift = (HashToUnit(x * 31 + seed, y * 37 + seed * 5, 777) - 0.5f) * intensity * 0.3f;
            var satShift = (HashToUnit(x * 41 + seed * 3, y * 43 + seed * 7, 888) - 0.5f) * intensity * 0.2f;

            // Simple hue rotation approximation in RGB
            var cosA = MathF.Cos(hueShift * MathF.PI * 2f);
            var sinA = MathF.Sin(hueShift * MathF.PI * 2f);
            var nr = lum + (r - lum) * cosA - (g - b) * 0.577f * sinA;
            var ng = lum + (g - lum) * cosA - (b - r) * 0.577f * sinA;
            var nb = lum + (b - lum) * cosA - (r - g) * 0.577f * sinA;

            // Apply saturation shift
            var sat = 1f + satShift;
            nr = lum + (nr - lum) * sat;
            ng = lum + (ng - lum) * sat;
            nb = lum + (nb - lum) * sat;

            r = Math.Clamp(nr, 0f, 1f);
            g = Math.Clamp(ng, 0f, 1f);
            b = Math.Clamp(nb, 0f, 1f);
        }
        else
        {
            // More aggressive: swap channel correlations
            var mix = intensity * 0.3f;
            var nr = r * (1f - mix) + g * mix * 0.5f + b * mix * 0.5f;
            var ng = g * (1f - mix) + r * mix * 0.5f + b * mix * 0.5f;
            var nb = b * (1f - mix) + r * mix * 0.5f + g * mix * 0.5f;
            r = Math.Clamp(nr, 0f, 1f);
            g = Math.Clamp(ng, 0f, 1f);
            b = Math.Clamp(nb, 0f, 1f);
        }

        output.SetPixel(x, y, r, g, b, a);
    });
    }
